'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { format } from 'date-fns'
import { toast } from 'sonner'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { deleteTerm } from '@/features/term/actions'
import { TermForm } from './TermForm'

interface TermWordItem {
    termId: number
    wordId: number
    seqNo: number
    word: { id: number; wordKor: string; wordEng: string; wordAbbr: string | null }
}

interface TermItem {
    id: number
    termKor: string
    termEng: string
    termAbbr: string | null
    termWords: TermWordItem[]
    createdAt: Date
}

interface TermDetailPanelProps {
    term: TermItem | null
    open: boolean
    onOpenChange: (open: boolean) => void
}

export function TermDetailPanel({ term, open, onOpenChange }: TermDetailPanelProps) {
    const router = useRouter()
    const [editOpen, setEditOpen] = useState(false)
    const [deleting, setDeleting] = useState(false)

    const handleDelete = async () => {
        if (!term) return
        if (!confirm(`"${term.termKor}" 용어를 삭제하시겠습니까?`)) return

        setDeleting(true)
        try {
            const result = await deleteTerm(term.id)
            if (!result.success) {
                toast.error(result.error ?? '삭제 중 오류가 발생했습니다')
                return
            }
            toast.success('용어가 삭제되었습니다')
            onOpenChange(false)
            router.refresh()
        } catch {
            toast.error('삭제 중 오류가 발생했습니다')
        } finally {
            setDeleting(false)
        }
    }

    if (!term) return null

    const wordList = term.termWords
        .sort((a, b) => a.seqNo - b.seqNo)
        .map((tw) => tw.word.wordKor)
        .join(', ')

    return (
        <>
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent className="sm:max-w-[480px]">
                    <DialogHeader>
                        <DialogTitle>용어 상세</DialogTitle>
                    </DialogHeader>
                    <dl className="grid grid-cols-[120px_1fr] gap-x-4 gap-y-3 text-sm">
                        <dt className="font-medium text-slate-500">ID</dt>
                        <dd>{term.id}</dd>
                        <dt className="font-medium text-slate-500">한글명</dt>
                        <dd>{term.termKor}</dd>
                        <dt className="font-medium text-slate-500">영문명</dt>
                        <dd>{term.termEng}</dd>
                        <dt className="font-medium text-slate-500">약어</dt>
                        <dd>{term.termAbbr ?? '-'}</dd>
                        <dt className="font-medium text-slate-500">구성단어</dt>
                        <dd>{wordList || '-'}</dd>
                        <dt className="font-medium text-slate-500">등록일</dt>
                        <dd>{format(new Date(term.createdAt), 'yyyy-MM-dd')}</dd>
                    </dl>
                    <div className="flex justify-end gap-2 pt-4">
                        <Button
                            variant="destructive"
                            onClick={handleDelete}
                            disabled={deleting}
                        >
                            {deleting ? '삭제 중...' : '삭제'}
                        </Button>
                        <Button variant="outline" onClick={() => setEditOpen(true)}>
                            수정
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>

            <TermForm
                open={editOpen}
                onOpenChange={setEditOpen}
                term={term}
                onSuccess={() => onOpenChange(false)}
            />
        </>
    )
}

