import { useState } from 'react'
import { format } from 'date-fns'
import type { ColDef, ValueFormatterParams } from 'ag-grid-community'
import { DataTable } from '@/components/ui/data-table'
import { Button } from '@/components/ui/button'
import { TermForm } from './TermForm'
import { TermDetailPanel } from './TermDetailPanel'

interface TermWordItem {
    termId: number
    wordId: number
    seqNo: number
    word: { id: number; wordKor: string; wordEng: string; wordAbbr: string | null }
}

interface TermItem {
    id: number
    termKor: string
    termEng: string
    termAbbr: string | null
    termWords: TermWordItem[]
    createdAt: Date
}

interface TermTableProps {
    items: TermItem[]
}

const columnDefs: ColDef<TermItem>[] = [
    { field: 'termKor', headerName: '한글명', flex: 1 },
    { field: 'termEng', headerName: '영문명', flex: 1 },
    { field: 'termAbbr', headerName: '약어', width: 150 },
    {
        headerName: '구성단어 수',
        width: 120,
        valueGetter: (params) => params.data?.termWords.length ?? 0,
    },
    {
        field: 'createdAt',
        headerName: '등록일',
        width: 150,
        valueFormatter: (params: ValueFormatterParams<TermItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd') : '',
    },
]

export function TermTable({ items }: TermTableProps) {
    const [createOpen, setCreateOpen] = useState(false)
    const [selectedTerm, setSelectedTerm] = useState<TermItem | null>(null)
    const [detailOpen, setDetailOpen] = useState(false)

    const handleRowClick = (row: TermItem) => {
        setSelectedTerm(row)
        setDetailOpen(true)
    }

    return (
        <div>
            <div className="flex justify-end mb-2">
                <Button onClick={() => setCreateOpen(true)}>새 용어</Button>
            </div>

            <DataTable<TermItem>
                columnDefs={columnDefs}
                rowData={items}
                onRowClick={handleRowClick}
            />

            <TermForm
                open={createOpen}
                onOpenChange={setCreateOpen}
                onSuccess={() => {}}
            />

            <TermDetailPanel
                term={selectedTerm}
                open={detailOpen}
                onOpenChange={setDetailOpen}
            />
        </div>
    )
}

