const columnDefs: ColDef<TermItem>[] = [
    { field: 'termKor', headerName: '한글명', flex: 1 },
    { field: 'termEng', headerName: '영문명', flex: 1 },
    { field: 'termAbbr', headerName: '약어', width: 150 },
    {
        headerName: '구성단어 수',
        width: 120,
        valueGetter: (params) => params.data?.termWords.length ?? 0,
    },
    {
        field: 'createdAt',
        headerName: '등록일',
        width: 150,
        valueFormatter: (params: ValueFormatterParams<TermItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd') : '',
    },
]

export function TermTable({ items }: TermTableProps) {
    const [createOpen, setCreateOpen] = useState(false)
    const [selectedTerm, setSelectedTerm] = useState<TermItem | null>(null)
    const [detailOpen, setDetailOpen] = useState(false)

    const handleRowClick = (row: TermItem) => {
        setSelectedTerm(row)
        setDetailOpen(true)
    }

    return (
        <div>
            <div className="flex justify-end mb-2">
                <Button onClick={() => setCreateOpen(true)}>새 용어</Button>
            </div>

            <DataTable<TermItem>
                columnDefs={columnDefs}
                rowData={items}
                onRowClick={handleRowClick}
            />

            <TermForm
                open={createOpen}
                onOpenChange={setCreateOpen}
                onSuccess={() => {}}
            />

            <TermDetailPanel
                term={selectedTerm}
                open={detailOpen}
                onOpenChange={setDetailOpen}
            />
        </div>
    )
}

import { getTerms } from '@/features/term/queries'
import { termSearchSchema } from '@/features/term/schema'
import { PageHeader } from '@/components/ui/page-header'
import { TermSearchForm } from '@/features/term/components/TermSearchForm'
import { TermTable } from '@/features/term/components/TermTable'

export default async function TermPage({
    searchParams,
}: {
    searchParams: Promise<Record<string, string>>
}) {
    const params = termSearchSchema.parse(await searchParams)
    const { items, total } = await getTerms(params)

    return (
        <div>
            <PageHeader title="용어 관리" description={`총 ${total}건`} />
            <TermSearchForm defaultKeyword={params.keyword} />
            <TermTable items={items} />
        </div>
    )
}

